from collections import deque

class Solution:
    def rightSideView(self, root):
        if not root:
            return []
        out = []
        queue = deque([root])
        while queue:
            last = None
            for _ in range(len(queue)):
                last = queue.popleft()
                if last.left:
                    queue.append(last.left)
                if last.right:
                    queue.append(last.right)
            out.append(last.val)
        return out
